import vex
from beeai import Agent

# Initialize Vex client
vex_client = vex.Client(api_key="your-vex-api-key")

# Define insurance compliance checks
def insurance_guardrails(event):
    if event.type == 'tool_call':
        # Block protected class references
        protected_terms = ['race', 'gender', 'religion', 'zip_code_proxy']
        if any(term in event.input.lower() for term in protected_terms):
            vex_client.capture_violation('DISCRIMINATION_RISK', event)
            return {'block': True, 'reason': 'Protected class reference detected'}
    return {'allow': True}

# Register Vex listener on BeeAI agent
agent = Agent(name="insurance-underwriter")
agent.add_event_listener(vex_client.insurance_event_handler(insurance_guardrails))

from vex import MemoryMonitor

memory_monitor = MemoryMonitor(
    max_size_mb=50,
    alert_threshold=80,
    compliance_tags=['PII', 'claims_data']
)

@agent.on('memory_update')
def check_memory_growth(event):
    if memory_monitor.exceeds_threshold(event.memory_state):
        # Truncate sensitive data before persistence
        cleaned_state = redact_pii(event.memory_state)
        vex_client.log_event('MEMORY_TRUNCATED', cleaned_state)
        event.memory_state = cleaned_state[:memory_monitor.max_size]

def validate_insurance_tool(tool_call):
    permitted_sources = ['internal_underwriting_db', 'naic_verified_rates']

    if tool_call.source not in permitted_sources:
        vex_client.capture_violation(
            'FCRA_VIOLATION',
            {'tool': tool_call.name, 'source': tool_call.source}
        )
        return False

    # Encrypt PII in tool parameters
    if 'ssn' in tool_call.params:
        tool_call.params['ssn'] = encrypt_ssn(tool_call.params['ssn'])

    # Require explanation for rate decisions
    if 'premium' in tool_call.output:
        tool_call.output['explanation'] = generate_risk_explanation(tool_call)

    return True

agent.add_tool_validator(validate_insurance_tool)
